26	namespace slang_frontend {
27	
28	std::optional<LValue> LValue::analyze(
29			EvalContext &context, const ast::Expression &expr, bool silent)
30	{
31		ast_invariant(expr, expr.kind != ast::ExpressionKind::Streaming);
32	
33		if (!expr.type->isFixedSize()) {
34			if (!silent) {
35				auto &d = context.netlist.add_diag(diag::FixedSizeRequired, expr.sourceRange);
36				d << expr.type->toString();
37			}
38			return std::nullopt;
39		}
40	
41		switch (expr.kind) {
42		case ast::ExpressionKind::HierarchicalValue: {
43			const ast::ValueSymbol &symbol = expr.as<ast::ValueExpressionBase>().symbol;
44			if (!context.netlist.scopes_remap.count(symbol.getParentScope()) &&
45					!context.netlist.check_hier_ref(symbol, expr.sourceRange, silent)) {
46				return std::nullopt;
47			}
48		}
49			[[fallthrough]];
50		case ast::ExpressionKind::NamedValue: {
51			const ast::ValueSymbol &symbol = expr.as<ast::ValueExpressionBase>().symbol;
52			if (context.netlist.is_inferred_memory(symbol)) {
53				// Unless we are evaluating initial procedures, directly evaluating
54				// the memory as an assignment target is disallowed. Memory writes should
55				// be handled in `ProceduralContext::assign_rvalue_inner` before they
56				// would get here.
57				if (!(context.procedural &&
58							context.procedural->timing.kind == ProcessTiming::Initial)) {
59					if (!silent) {
60						context.netlist.add_diag(diag::BadMemoryExpr, expr.sourceRange);
61					}
62					return std::nullopt;
63				}
64			}
65	
66			if (symbol.kind == ast::SymbolKind::ModportPort &&
67					!context.netlist.scopes_remap.count(symbol.getParentScope())) {
68				return analyze(
69						context, *symbol.as<ast::ModportPortSymbol>().getConnectionExpr(), silent);
70			}
71	
72			Variable var = context.variable(symbol);
73			return LValue::variable(var);
74		}
75		case ast::ExpressionKind::RangeSelect: {
76			const ast::RangeSelectExpression &rse = expr.as<ast::RangeSelectExpression>();
77			ast_invariant(
78					expr, rse.value().type->isBitstreamType() && rse.value().type->hasFixedRange());
79			AddressingResolver resolver(context, rse);
80	
81			std::optional<LValue> inner = analyze(context, rse.value());
82			if (!inner)
83				return std::nullopt;
84	
85			return LValue::rangeSelect(
86					std::move(*inner), std::move(resolver), expr.type->getBitstreamWidth());
87		}
88		case ast::ExpressionKind::ElementSelect: {
89			// Handle element select as 1-item range select
90			const ast::ElementSelectExpression &ese = expr.as<ast::ElementSelectExpression>();
91			ast_invariant(
92					expr, ese.value().type->isBitstreamType() && ese.value().type->hasFixedRange());
93	
94			if (context.netlist.is_inferred_memory(ese.value()) &&
95					context.procedural->timing.kind != ProcessTiming::Initial) {
96				RTLIL::SigSpec address = context(ese.selector());
97				auto variable =
98						Variable::from_symbol(&ese.value().as<ast::ValueExpressionBase>().symbol);
99				return LValue::memoryWrite(variable, address, ese.type->getBitstreamWidth());
100			}
101	
102			std::optional<LValue> inner = analyze(context, ese.value());
103			if (!inner)
104				return std::nullopt;
105	
106			AddressingResolver addr(context, ese);
107	
108			return LValue::rangeSelect(
109					std::move(*inner), std::move(addr), expr.type->getBitstreamWidth());
110		}
111		case ast::ExpressionKind::Concatenation: {
112			std::vector<LValue> elements;
113			const ast::ConcatenationExpression &concat = expr.as<ast::ConcatenationExpression>();
114			for (auto operand : concat.operands()) {
115				auto element_lv = analyze(context, *operand, silent);
116				if (!element_lv)
117					return std::nullopt;
118				elements.push_back(std::move(*element_lv));
119			}
120			return LValue::concatenation(std::move(elements));
121		}
122		case ast::ExpressionKind::MemberAccess: {
123			const auto &acc = expr.as<ast::MemberAccessExpression>();
124	
125			std::optional<LValue> inner = analyze(context, acc.value());
126			if (!inner)
127				return std::nullopt;
128	
129			require(expr, acc.member.kind == ast::SymbolKind::Field);
130			const auto &member = acc.member.as<ast::FieldSymbol>();
131			require(expr, member.randMode == ast::RandMode::None);
132	
133			uint64_t bit_offset = bitstream_member_offset(member);
134	
135			return LValue::memberAccess(std::move(*inner), bit_offset, expr.type->getBitstreamWidth());
136		}
137		case ast::ExpressionKind::Conversion: {
138			const ast::ConversionExpression &conv = expr.as<ast::ConversionExpression>();
139			if (conv.operand().kind != ast::ExpressionKind::Streaming) {
140				const ast::Type &from = conv.operand().type->getCanonicalType();
141				const ast::Type &to = conv.type->getCanonicalType();
142				if (to.isBitstreamType() && from.isBitstreamType() &&
143						from.getBitstreamWidth() == to.getBitstreamWidth()) {
144					return analyze(context, conv.operand(), silent);
145				}
146			}
147		}
148			[[fallthrough]];
149		default:
150			if (!silent) {
151				context.netlist.add_diag(diag::UnsupportedLhs, expr.sourceRange);
152			}
153			return std::nullopt;
154		}
155	}
156	
157	LValue LValue::variable(Variable variable)
158	{
159		return LValue(variable, variable.bitwidth(), true, true);
160	}
161	
162	LValue LValue::concatenation(std::vector<LValue> elements)
163	{
164		uint64_t size_total = 0;
165		bool static_ = true;
166		for (auto &element : elements) {
167			size_total += element.bitsize;
168			static_ &= element.static_;
169		}
170		return LValue(Concatenation{std::move(elements)}, size_total, static_,
171				/* contiguous_slice_= */ false);
172	}
173	
174	LValue LValue::rangeSelect(LValue inner, AddressingResolver resolver, uint64_t bitsize)
175	{
176		bool static_ = inner.static_ && resolver.is_static();
177		bool contiguous_slice_ = inner.contiguous_slice_;
178		return LValue(RangeSelect{std::make_unique<AddressingResolver>(std::move(resolver)),
179							  std::make_unique<LValue>(std::move(inner))},
180				bitsize, static_, contiguous_slice_);
181	}
182	
183	LValue LValue::memberAccess(LValue inner, uint64_t base_offset, uint64_t bitsize)
184	{
185		bool static_ = inner.static_;
186		bool contiguous_slice_ = inner.contiguous_slice_;
187		return LValue(MemberAccess{base_offset, std::make_unique<LValue>(std::move(inner))}, bitsize,
188				static_, contiguous_slice_);
189	}
190	
191	LValue LValue::memoryWrite(Variable variable, RTLIL::SigSpec address, uint64_t bitsize)
192	{
193		return LValue(MemoryWrite{variable, address}, bitsize, false, false);
194	}
195	
196	bool LValue::is_static()
197	{
198		return static_;
199	}
200	
201	VariableBits LValue::evaluate_vbits()
202	{
203		log_assert(static_);
204	
205		if (auto variable = std::get_if<Variable>(&descriptor)) {
206			return *variable;
207		} else if (auto concat = std::get_if<Concatenation>(&descriptor)) {
208			VariableBits ret;
209			ret.reserve(bitsize);
210			auto &els = concat->elements;
211			for (auto it = els.rbegin(); it != els.rend(); it++)
212				ret.append(it->evaluate_vbits());
213			return ret;
214		} else if (auto range_sel = std::get_if<RangeSelect>(&descriptor)) {
215			auto inner_vbits = range_sel->inner->evaluate_vbits();
216			return range_sel->resolver->extract<VariableBits>(inner_vbits, bitsize);
217		} else if (auto member_acc = std::get_if<MemberAccess>(&descriptor)) {
218			auto inner_vbits = member_acc->inner->evaluate_vbits();
219			return inner_vbits.extract(member_acc->base_offset, bitsize);
220		} else {
221			// unreachable
222			log_abort();
223		}
224	}
225	
226	}; // namespace slang_frontend
