401			chunk_span_iterator begin() const { return chunk_span_iterator(bits, 0); };
402			chunk_span_iterator end() const { return chunk_span_iterator(bits, bits.bitwidth()); };
403	
404		protected:
405			chunk_span_list(const VariableBits &bits) : bits(bits) {};
406			friend class VariableBits;
407	
408		private:
409			const VariableBits &bits;
410		};
